        /// </summary>
        /// <param name="rootPath">Raiz do escopo de análise.</param>
        /// <param name="include">Pastas ou caminhos a incluir.</param>
        /// <param name="exclude">Pastas ou caminhos a excluir.</param>
        /// <returns>Modelo estrutural gerado.</returns>
