namespace RefactorScope.Core.Orchestration
{
    /// <summary>
    /// Representa o relatório consolidado da execução.
    ///
    /// 🔒 Fonte Única de Verdade para classificação de Zombies.
    ///
    /// Separação formal:
    /// - Structural Candidates (ausência estrutural)
    /// - Confirmed Zombies (após threshold probabilístico)
    /// - Suspicious (candidatos abaixo do threshold)
    /// - Absolved (candidatos estruturais não confirmados)
    /// </summary>
    public class ConsolidatedReport
    {
        public IReadOnlyCollection<IAnalysisResult> Results { get; }
        public DateTime ExecutionTime { get; }
        public string TargetScope { get; }

        /// <summary>
        /// Threshold aplicado para confirmação probabilística.
        /// </summary>
        public double ZombieProbabilityThreshold { get; }

        public ConsolidatedReport(
            IReadOnlyCollection<IAnalysisResult> results,
            DateTime executionTime,
            string targetScope,
            double zombieProbabilityThreshold)
        {
            Results = results;
            ExecutionTime = executionTime;
            TargetScope = targetScope;
            ZombieProbabilityThreshold = zombieProbabilityThreshold;
        }

        // ==========================================================
        // 🔹 Acesso Genérico
        // ==========================================================

        public T? GetResult<T>() where T : class, IAnalysisResult
            => Results.OfType<T>().FirstOrDefault();

        // ==========================================================
        // 🔹 Camada 1 — Structural Candidates
        // ==========================================================

        public IReadOnlyList<string> GetStructuralCandidates()
        {
            var structural = GetResult<ZombieResult>();
            return structural?.ZombieTypes ?? new List<string>();
        }

        // ==========================================================
        // 🔹 Camada 2 — Confirmed Zombies
        // ==========================================================

        public IReadOnlyList<string> GetConfirmedZombies()
        {
            var probabilistic = GetResult<ZombieProbabilityResult>();

            if (probabilistic == null)
                return new List<string>();

            return probabilistic
                .ConfirmedZombies(ZombieProbabilityThreshold)
                .Select(x => x.TypeName)
                .ToList();
        }

        /// <summary>
        /// Compatibilidade retroativa.
        /// </summary>
        public IReadOnlyList<string> GetEffectiveZombieTypes()
            => GetConfirmedZombies();

        // ==========================================================
        // 🔹 Camada 3 — Suspicious
        // ==========================================================

        public IReadOnlyList<string> GetSuspiciousZombies()
        {
            var probabilistic = GetResult<ZombieProbabilityResult>();

            if (probabilistic == null)
                return new List<string>();

            return probabilistic.Items
                .Where(i => i.Probability < ZombieProbabilityThreshold)
                .Select(i => i.TypeName)
                .ToList();
        }

        // ==========================================================
        // 🔹 Camada 4 — Absolved
        // ==========================================================

        public IReadOnlyList<string> GetAbsolvedZombies()
        {
            var structural = GetStructuralCandidates();
            var confirmed = GetConfirmedZombies();

            return structural
                .Where(s => !confirmed.Contains(s))
                .ToList();
        }

        // ==========================================================
        // 🔹 Breakdown Oficial
        // ==========================================================

        public ZombieAnalysisBreakdown GetZombieBreakdown()
        {
            var structural = GetStructuralCandidates();
            var confirmed = GetConfirmedZombies();
            var suspicious = GetSuspiciousZombies();
            var absolved = GetAbsolvedZombies();

            var reduction = structural.Count == 0
                ? 0
                : (structural.Count - confirmed.Count) / (double)structural.Count;

            return new ZombieAnalysisBreakdown(
                structural.Count,
                confirmed.Count,
                suspicious.Count,
                absolved.Count,
                reduction
            );
        }

        public double GetZombieRate(int totalTypes)
        {
            if (totalTypes == 0) return 0;
            return GetConfirmedZombies().Count / (double)totalTypes;
        }
    }
}

using System.Text;
using RefactorScope.Core.Orchestration;
using RefactorScope.Core.Results;

namespace RefactorScope.Core.Reporting
{
    /// <summary>
    /// Exporta relatório arquitetural em formato Markdown.
    /// Utiliza Zombie efetivo (probabilístico se disponível).
    /// </summary>
    public sealed class MarkdownReportExporter
    {
        public void Export(ConsolidatedReport report, string outputPath)
        {
            var sb = new StringBuilder();

            var architecture = report.GetResult<ArchitecturalClassificationResult>();
            var isolated = report.GetResult<CoreIsolationResult>();
            var coupling = report.GetResult<CouplingResult>();
            var fitness = report.GetResult<FitnessGateResult>();

            if (architecture == null)
                return;

            var threshold = 0.60;
            var effectiveZombies = report.GetEffectiveZombieTypes();

            sb.AppendLine("# 🧬 RefactorScope – Relatório Arquitetural");
            sb.AppendLine();
            sb.AppendLine($"📅 **Execution Time:** {report.ExecutionTime:yyyy-MM-dd HH:mm} UTC  ");
            sb.AppendLine($"📂 **Target Scope:** `{report.TargetScope}`  ");
            sb.AppendLine();
            sb.AppendLine("---");
            sb.AppendLine();
            sb.AppendLine("## 🏥 Architectural Health by Module");
            sb.AppendLine();

            var modules = architecture.Items.GroupBy(i => i.Folder);

            foreach (var module in modules)
            {
                var total = module.Count();
                if (total == 0) continue;

                var zombieCount = effectiveZombies
                    .Count(z => module.Any(m => m.TypeName == z));

                var isolatedCount = isolated?.IsolatedCoreTypes
                    .Count(i => module.Any(m => m.TypeName == i)) ?? 0;

                var fanOut = coupling?.ModuleFanOut
                    .GetValueOrDefault(module.Key) ?? 0;

                var zombieRate = zombieCount / (double)total;
                var isolationRate = isolatedCount / (double)total;
                var couplingRate = fanOut / (double)total;
                var coreDensity = module.Count(t => t.Layer == "Core") / (double)total;

                var score =
                    100
                    - (couplingRate * 30)
                    - (zombieRate * 25)
                    - (isolationRate * 20)
                    + (coreDensity * 15);

                score = Math.Max(0, Math.Min(100, score));

                var scoreEmoji = score >= 70 ? "🟢"
                                 : score >= 40 ? "🟡"
                                 : "🔴";

                sb.AppendLine($"### {scoreEmoji} {module.Key}");
                sb.AppendLine();
                sb.AppendLine($"- **Score:** `{score:0.0}`");
                sb.AppendLine($"- **Zombies:** {(zombieCount > 0 ? "🔴" : "🟢")} {zombieCount} ({zombieRate:0%})");
                sb.AppendLine($"- **Coupling:** {couplingRate:0.00}");
                sb.AppendLine($"- **Isolation:** {isolationRate:0.00}");
                sb.AppendLine();
            }

            if (fitness != null)
            {
                sb.AppendLine("---");
                sb.AppendLine();
                sb.AppendLine("## 🚦 Fitness Gates");
                sb.AppendLine();

                foreach (var gate in fitness.Gates)
                {
                    var emoji = gate.Status switch
                    {
                        GateStatus.Pass => "🟢",
                        GateStatus.Warn => "🟡",
                        GateStatus.Fail => "🔴",
                        _ => "⚪"
                    };

                    sb.AppendLine($"- {emoji} **{gate.GateName}** {gate.Message}");
                }

                sb.AppendLine();
                sb.AppendLine(fitness.HasFailure
                    ? "🔴 **Arquitetura NÃO pronta para CI/CD**"
                    : "🟢 **Arquitetura pronta para CI/CD**");
            }

            sb.AppendLine();
            sb.AppendLine("---");
            sb.AppendLine();
            sb.AppendLine("_Generated by RefactorScope_");

            File.WriteAllText(outputPath, sb.ToString());
        }
    }
}

